        if organization_name or organization_url:
            org_name = self._xml_escape(organization_name or "")
            org_url = self._xml_escape(organization_url or "")
            metadata += (
                '<md:Organization>'
                f'<md:OrganizationName xml:lang="en">{org_name}</md:OrganizationName>'
                f'<md:OrganizationDisplayName xml:lang="en">{org_name}</md:OrganizationDisplayName>'
                f'<md:OrganizationURL xml:lang="en">{org_url}</md:OrganizationURL>'
                '</md:Organization>'
            )

        # Add Contact info
